There is some simple style cleanup that could be done here: Using UpperCamelCase for clases, structs, and functions, dropping static methods in favour of a constructor, and dropping the seemingly unused `connect` bool:

<details>
<summary>Click to expand diff</summary>

```diff
diff --git a/src/test/sock_tests.cpp b/src/test/sock_tests.cpp
index 0cd5072758..2353b1b933 100644
--- a/src/test/sock_tests.cpp
+++ b/src/test/sock_tests.cpp
@@ -84 +84 @@ BOOST_AUTO_TEST_CASE(move_assignment)
-struct tcp_socket_pair {
+struct TcpSocketPair {
@@ -88 +88,3 @@ struct tcp_socket_pair {
-    static tcp_socket_pair create(bool connect)
+    TcpSocketPair()
+        : sender{std::make_unique<Sock>(CreateSocket())},
+        receiver{std::make_unique<Sock>(CreateSocket())}
@@ -90,6 +92 @@ struct tcp_socket_pair {
-        tcp_socket_pair socks{};
-        socks.sender = std::make_unique<Sock>(CreateSocket());
-        socks.receiver = std::make_unique<Sock>(CreateSocket());
-        if (connect) socks.connect_pair();
-
-        return socks;
+        Connect();
@@ -98 +95 @@ struct tcp_socket_pair {
-    void connect_pair()
+    void Connect()
@@ -122 +119 @@ struct tcp_socket_pair {
-    void send_and_receive()
+    void SendAndReceive()
@@ -136,2 +133,2 @@ BOOST_AUTO_TEST_CASE(send_and_receive)
-    tcp_socket_pair socks = tcp_socket_pair::create(/*connect=*/true);
-    socks.send_and_receive();
+    TcpSocketPair socks;
+    socks.SendAndReceive();
@@ -140,2 +137,2 @@ BOOST_AUTO_TEST_CASE(send_and_receive)
-    tcp_socket_pair socks_moved = std::move(socks);
-    socks_moved.send_and_receive();
+    TcpSocketPair socks_moved = std::move(socks);
+    socks_moved.SendAndReceive();
@@ -146 +143 @@ BOOST_AUTO_TEST_CASE(wait)
-    tcp_socket_pair socks = tcp_socket_pair::create(/*connect=*/true);
+    TcpSocketPair socks;
@@ -160 +157 @@ BOOST_AUTO_TEST_CASE(recv_until_terminator_limit)
-    tcp_socket_pair socks = tcp_socket_pair::create(/*connect=*/true);
+    TcpSocketPair socks;
```

